    ];
    autoTable(doc, {
        startY: 35,
        head: [['Parámetro', 'Valor', 'Parámetro', 'Valor']],
        body: datosBody,
        theme: 'grid',
        headStyles: { fillColor: [41, 128, 185] },
    });

    let finalY = (doc as any).lastAutoTable.finalY || 60;

    // -- NEW: Vehicle Composition Table (If method is 'vehicles') --
    if (method === 'vehicles') {
        doc.setFontSize(14);
        doc.text("Composición Vehicular", 14, finalY + 10);

        // Filter out vehicles with 0% participation
        const vehData = VEHICLE_NAMES.map((name, index) => ({
            name,
