    });

    finalY = (doc as any).lastAutoTable.finalY || 150;
    if (finalY > 230) { doc.addPage(); finalY = 20; }

    // Structure
    const totalSnReal = structureLayers.reduce((acc, layer) => acc + (layer.snProvided || 0), 0);
    doc.setFontSize(14);
    doc.text("Estructura de Pavimento", 14, finalY + 10);
    doc.setFontSize(10);
    doc.text(`SN Requerido (Subrasante): ${formatNum(snRequiredTotalManual, 2)}`, 14, finalY + 18);
    doc.text(`SN Real Total: ${formatNum(totalSnReal, 2)}`, 110, finalY + 18);

    autoTable(doc, {
