        body: structureLayers.map(l => [
            l.name, l.a, l.m, formatNum(l.supportMr, 0), formatNum(l.snReq, 2), formatNum(l.h_cm_calc, 2), l.h_cm_real.toFixed(1)
        ]),
        theme: 'grid',
        headStyles: { fillColor: [155, 89, 182] }
    });

    // Add Subgrade Row
    autoTable(doc, {
        startY: (doc as any).lastAutoTable.finalY,
