                    <label className="block text-sm font-semibold text-slate-400 mb-1">SN Semilla</label>
                    <input 
                        type="number" step="0.01" value={snSeed}
                        onChange={(e) => setSnSeed(parseFloat(e.target.value) || 0)}
                        className="w-full bg-slate-900 border border-slate-600 rounded px-4 py-3 text-white focus:border-blue-500 focus:outline-none font-mono text-lg"
                    />
