                    {snRequiredTotalManual > 0 && (
                        <div className="absolute right-4 top-1/2 -translate-y-1/2">
                             <button onClick={() => setSnSeed(Number(snRequiredTotalManual.toFixed(2)))} className="w-10 h-10 rounded-full bg-blue-600 hover:bg-blue-500 text-white flex items-center justify-center transition-all shadow-lg">
