             <div className="text-3xl font-mono font-bold text-white mt-1">{formatNum(totalESALs1Year, 0)}</div>
        </div>
        <div className="bg-gradient-to-br from-emerald-900/50 to-slate-900 border border-emerald-800/50 p-6 rounded-xl">
             <div className="text-emerald-400 text-sm font-bold uppercase">Total ESALs Diseño</div>
             <div className="text-3xl font-mono font-bold text-white mt-1">{formatNum(totalESALsDesign, 0)}</div>
        </div>
      </div>

      {/* Detail Table */}
      <div className="bg-slate-900 border border-slate-700 rounded-xl overflow-hidden shadow-xl mb-8">
        <div className="overflow-x-auto">
            <table className="w-full text-sm text-left text-slate-400">
                <thead className="text-xs text-slate-200 uppercase bg-slate-800">
                    <tr>
                        <th className="px-4 py-3 text-center">No.</th>
                        <th className="px-4 py-3">Tipo</th>
                        <th className="px-4 py-3 text-center text-blue-300">L2</th>
                        <th className="px-4 py-3 text-right text-blue-300">Lx (kip)</th>
                        <th className="px-4 py-3 text-right">Ejes 1er Año</th>
                        <th className="px-4 py-3 text-right text-emerald-400">Fx</th>
                        <th className="px-4 py-3 text-right font-bold text-white bg-slate-700">ESAL Diseño</th>
                    </tr>
                </thead>
                <tbody>
                    {esalRows.map((row, index) => (
                        <tr key={index} className="border-b border-slate-800 hover:bg-slate-800/50">
                            <td className="px-4 py-3 text-center">{row.no}</td>
                            <td className="px-4 py-3 font-medium text-slate-200">{row.tipo}</td>
                            <td className="px-4 py-3 text-center font-mono">{row.l2}</td>
                            <td className="px-4 py-3 text-right font-mono">{formatNum(row.lxKip)}</td>
                            <td className="px-4 py-3 text-right">{Math.round(row.ejesAnio).toLocaleString()}</td>
                            <td className="px-4 py-3 text-right font-mono text-emerald-400">{formatNum(row.fx, 4)}</td>
                            <td className="px-4 py-3 text-right font-bold text-white bg-slate-800/30 font-mono">
                                {formatNum(row.esalAnio * growthFactor)}
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
      </div>

       <div className="flex flex-col sm:flex-row justify-end gap-4">
            <button onClick={handleSaveCalculations} className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-3 rounded-lg font-bold shadow-lg">
                <i className="fas fa-save"></i> Guardar
            </button>
            <button onClick={generatePDF} className="bg-red-600 hover:bg-red-500 text-white px-6 py-3 rounded-lg font-bold shadow-lg">
                <i className="fas fa-file-pdf"></i> PDF
            </button>
        </div>
        {isSaved && (
            <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-green-500 text-white px-6 py-3 rounded-lg shadow-lg animate-bounce pointer-events-none">
                <i className="fas fa-check-circle"></i> Guardado
            </div>
        )}
    </div>
  );
};

export default EsalsPage;

import React, { useState, useEffect, useMemo } from 'react';
import { GeneralData, CompositionData, PavementLayer, CalculationMethod, AxleInputRow } from '../types';
import { DEFAULT_COMPOSITION, DEFAULT_GENERAL_DATA, TABLE_STATIC_ROWS, VEHICLE_NAMES } from '../constants';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

// Approximation of Inverse Standard Normal Distribution (Probit)
function inverseNormalCDF(p: number): number {
    if (p <= 0 || p >= 1) return 0;
    const t = Math.sqrt(-2 * Math.log(p < 0.5 ? p : 1 - p));
    const c0 = 2.515517;
    const c1 = 0.802853;
    const c2 = 0.010328;
    const d1 = 1.432788;
    const d2 = 0.189269;
    const d3 = 0.001308;

    const x = t - ((c2 * t + c1) * t + c0) / (((d3 * t + d2) * t + d1) * t + 1);
    return p < 0.5 ? -x : x;
}

// Helper for Mobile Abbreviations
const getMobileLayerName = (layer: PavementLayer) => {
    if (layer.customCode) return layer.customCode;
    switch (layer.name) {
        case "Carpeta asfáltica alto desempeño": return "AD";
        case "Carpeta asfáltica normal": return "CA";
        case "Base asfáltica": return "BA";
        case "Base Cementada": return "BC";
        case "Base hidráulica": return "BH";
        case "Sub-Base Hidráulica": return "SB";
        default: return layer.name.substring(0, 4);
    }
};

const EsalsPage: React.FC = () => {
  // Inputs for AASHTO Design
  const [snSeed, setSnSeed] = useState<number>(2.0); 
  const [manualThicknesses, setManualThicknesses] = useState<Record<string, number>>({});
  const [isSaved, setIsSaved] = useState(false);

  // Data from previous steps
  const [method, setMethod] = useState<CalculationMethod>('vehicles');
  const [genData, setGenData] = useState<GeneralData>(DEFAULT_GENERAL_DATA);
  const [compData, setCompData] = useState<CompositionData>(DEFAULT_COMPOSITION);
  const [directRows, setDirectRows] = useState<AxleInputRow[]>([]);

  useEffect(() => {
    // Load general inputs
    const savedGen = localStorage.getItem('datosGeneralesData');
    if (savedGen) setGenData({ ...DEFAULT_GENERAL_DATA, ...JSON.parse(savedGen) });

    // Load Calculation Method
    const savedMethod = localStorage.getItem('calculationMethod') as CalculationMethod | null;
    if (savedMethod) setMethod(savedMethod);

    // Load Traffic Data sources
    const savedComp = localStorage.getItem('compVehData');
    if (savedComp) setCompData(JSON.parse(savedComp));

    const savedDirect = localStorage.getItem('directAxleData');
    if (savedDirect) setDirectRows(JSON.parse(savedDirect));

    // Load saved calculations specific to this page
    const savedEsals = localStorage.getItem('esalsData');
    if (savedEsals) {
        try {
            const parsed = JSON.parse(savedEsals);
            if (parsed.snSeed !== undefined) setSnSeed(parsed.snSeed);
            if (parsed.manualThicknesses) setManualThicknesses(parsed.manualThicknesses);
        } catch (e) { console.error(e); }
    }
  }, []);

  const handleSaveCalculations = () => {
      const dataToSave = { snSeed, manualThicknesses };
      localStorage.setItem('esalsData', JSON.stringify(dataToSave));
      setIsSaved(true);
      setTimeout(() => setIsSaved(false), 3000);
  };

  // --- 1. PREPARE TRAFFIC DATA STREAM ---
  // Returns a unified structure of { id, no, tipo, l2, lxKip, count }
  const trafficStream = useMemo(() => {
      if (method === 'direct') {
          // Direct Mode: Use the user entered rows directly
          return directRows.map((r, i) => ({
              id: r.id,
              no: i + 1,
              tipo: r.l2 === 1 ? 'Sencillo' : r.l2 === 2 ? 'Tándem' : 'Trídem',
              l2: r.l2,
              lxKip: r.lxKip,
              count: r.count
          }));
      } else {
          // Vehicle Mode: Calculate derived axles first (from AxlePage logic)
          const compObj: Record<string, number> = {};
          VEHICLE_NAMES.forEach((name, idx) => { compObj[name] = compData[idx] || 0; });
          const getVal = (key: string) => compObj[key] || 0;

          const Pvc = genData.pvc;
          const TDPA = genData.tdpa;
          let fcp = 0.5;
          if (genData.lanes === '2') fcp = 0.45;
          if (genData.lanes === '3+') fcp = 0.4;
          const TDPAcd = fcp * TDPA;
          const fvp = 0.0365 * Pvc * TDPAcd;
          const fvv = 0.0365 * (100 - Pvc) * TDPAcd;

          const formulas = [
              () => 2 * getVal("A2") * (fvp + fvv),
              () => (100 - getVal("A2") + getVal("B4")) * fvp,
              () => (getVal("B2") + getVal("C2") + getVal("T2S1") + getVal("T2S2") + getVal("T2S3") + getVal("T2S2S2")) * fvp,
              () => (2*getVal("C2R2") + 2*getVal("C3R2") + getVal("C3R3") + getVal("C2R3") + 3*getVal("T2S1R2") + 2*getVal("T2S1R3") + 2*getVal("T2S2R2") + 3*getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + getVal("T3S2R3")) * fvp,
              () => (getVal("T2S1") + getVal("T3S1")) * fvp,
              () => (getVal("C2R2") + getVal("C2R3") + getVal("T2S1R2") + getVal("T2S1R3") + getVal("T2S2R2")) * fvp,
              () => (getVal("B2") + getVal("B36") + getVal("B38") + 2*getVal("B4") + 2*getVal("C2") + getVal("C36") + getVal("C38") + 4*getVal("C2R2") + 3*getVal("C3R2") + 2*getVal("C3R3") + 3*getVal("C2R3") + 3*getVal("T2S1") + 2*getVal("T2S2") + getVal("T3S2") + getVal("T3S3") + 2*getVal("T3S1") + 5*getVal("T2S1R2") + 4*getVal("T2S1R3") + 4*getVal("T2S2R2") + 4*getVal("T3S1R2") + 3*getVal("T3S1R3") + 3*getVal("T3S2R2") + getVal("T3S2R4") + 2*getVal("T3S2R3") + getVal("T3S3S2") + 2*getVal("T2S2S2") + getVal("T3S2S2")) * fvv,
              () => (getVal("B2") + getVal("B36") + getVal("B38") + getVal("B4")) * fvv,
              () => (getVal("B36") + getVal("B4") + getVal("C36") + getVal("T3S1R3")) * fvp,
              () => (getVal("B38") + getVal("C38") + getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T3S2S2")) * fvp,
              () => (getVal("C3R3") + getVal("C2R3") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R3") + getVal("T3S2R2") + 3*getVal("T3S2R4") + 2*getVal("T3S2R3") + 2*getVal("T2S2S2") + 2*getVal("T3S2S2")) * fvp,
              () => (getVal("T2S2") + getVal("T3S2") + getVal("T3S3S2")) * fvp,
              () => (getVal("C3R2") + getVal("C3R3") + getVal("T3S1R2") + getVal("T3S2R2") + getVal("T3S2R4") + getVal("T3S2R3") + getVal("T3S3S2")) * fvp,
              () => (getVal("C36") + getVal("C38") + getVal("C3R2") + 2*getVal("C3R3") + getVal("C2R3") + getVal("T2S2") + 2*getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + 4*getVal("T3S2R4") + 3*getVal("T3S2R3") + 2*getVal("T3S3S2") + 2*getVal("T2S2S2") + 3*getVal("T3S2S2")) * fvv,
              () => getVal("T3S3S2") * fvp,
              () => (getVal("T3S3") + getVal("T2S3")) * fvp,
              () => getVal("T3S3S2") * fvv
          ];

          return TABLE_STATIC_ROWS.map((staticRow, index) => {
              // Determine L2 (Axle type code) from static row type
              let l2 = 1;
              if (staticRow[1] === "Tándem") l2 = 2;
              if (staticRow[1] === "Trídem") l2 = 3;

              // Determine Weight (Lx) from Road Type (ET_A, B, C, D)
              let weightTon = 0;
              switch(genData.roadType) {
                  case 'ET_A': weightTon = staticRow[4]; break;
                  case 'B':    weightTon = staticRow[5]; break;
                  case 'C':    weightTon = staticRow[6]; break;
                  case 'D':    weightTon = staticRow[7]; break;
                  default:     weightTon = staticRow[4];
              }
              const lxKip = weightTon * 2.20462; 

              const count = formulas[index] ? formulas[index]() : 0;

              return {
                  id: `v_row_${index}`,
                  no: staticRow[0],
                  tipo: staticRow[1],
                  l2,
                  lxKip,
                  count
              };
          });
      }
  }, [method, directRows, genData, compData]);


  // --- 2. CALCULATE ESALS (Fx Calculation) ---
  const { esalRows, growthFactor } = useMemo(() => {
    const log10 = Math.log10;
    const pow = Math.pow;

    // Gt
    const pt = genData.finalServiceability;
    const Gt = log10((4.2 - pt) / 2.7);

    // Beta 18
    const beta18 = 0.4 + (1094 / pow(snSeed + 1, 5.19));

    // Growth Factor
    const r = genData.growthRate / 100;
    const n = genData.designPeriod;
    let gf = n; 
    if (r !== 0) {
        gf = (pow(1 + r, n) - 1) / r;
    }

    // Map the Unified Traffic Stream
    const rows = trafficStream.map(item => {
        const { l2, lxKip, count } = item;

        // Fx Calculation 
        // 1. Beta X
        const numeratorBx = 0.081 * pow(lxKip + l2, 3.23);
        const denominatorBx = pow(snSeed + 1, 5.19) * pow(l2, 3.23);
        const betaX = 0.4 + (numeratorBx / denominatorBx);

        // 2. Fx Exponent
        const term1 = 4.79 * log10(18 + 1); 
        const term2 = 4.79 * log10(lxKip + l2);
        const term3 = 4.33 * log10(l2);
        const term4 = Gt / betaX;
        const term5 = Gt / beta18;

        const exponent = term1 - term2 + term3 + term4 - term5;
        const fx = 1 / pow(10, exponent);

        const esal = fx * count;

        return {
            ...item,
            ejesAnio: count,
            fx,
            esalAnio: esal
        };
    });

    return { esalRows: rows, growthFactor: gf };
  }, [snSeed, genData.finalServiceability, genData.growthRate, genData.designPeriod, trafficStream]);

  const totalESALs1Year = useMemo(() => esalRows.reduce((acc, r) => acc + r.esalAnio, 0), [esalRows]);
  const totalESALsDesign = totalESALs1Year * growthFactor;

  // --- 3 & 4. SN CALCULATIONS (Same as before) ---
  const solveAashtoIterative = (Mr: number, W18: number): number => {
    if (W18 <= 0 || Mr <= 0) return 0;
    const log10 = Math.log10;
    const pow = Math.pow;
    const abs = Math.abs;
    const p = 1 - (genData.reliability / 100);
    const Zr = inverseNormalCDF(p);
    const So = genData.standardDeviation;
    const Pt = genData.finalServiceability;
    const dPSI = 4.2 - Pt; 
    const logW18 = log10(W18);
    const zrSo = Zr * So;
    const logMrTerm = 2.32 * log10(Mr);
    const psiTerm = log10(dPSI / 2.7); 
    let currentSeed = 2.0; 
    let snReq = 0;
    let error = 1.0;
    let iterations = 0;
    while (error > 0.001 && iterations < 100) {
        iterations++;
        const denominator = 0.4 + (1094 / pow(currentSeed + 1, 5.19));
        const fraction = psiTerm / denominator;
        const beta = logW18 - zrSo - fraction - logMrTerm + 8.27;
        snReq = -1 + pow(10, beta / 9.36);
        error = abs(snReq - currentSeed);
        if (error >= 0.001) currentSeed = snReq;
    }
    return snReq > 0 ? snReq : 0;
  };

  const calculateManualSN = (Mr: number, W18: number, seed: number): number => {
    if (W18 <= 0 || Mr <= 0) return 0;
    const log10 = Math.log10;
    const pow = Math.pow;
    const p = 1 - (genData.reliability / 100);
    const Zr = inverseNormalCDF(p);
    const So = genData.standardDeviation;
    const Pt = genData.finalServiceability;
    const dPSI = 4.2 - Pt;
    const logW18 = log10(W18);
    const zrSo = Zr * So;
    const logMrTerm = 2.32 * log10(Mr);
    const psiTerm = log10(dPSI / 2.7);
    const denominator = 0.4 + (1094 / pow(seed + 1, 5.19));
    const fraction = psiTerm / denominator;
    const beta = logW18 - zrSo - fraction - logMrTerm + 8.27;
    const snReq = -1 + pow(10, beta / 9.36);
    return snReq > 0 ? snReq : 0;
  };

  const snRequiredTotalManual = useMemo(() => {
    return calculateManualSN(genData.subgradeMr, totalESALsDesign, snSeed);
  }, [totalESALsDesign, genData, snSeed]);


  // --- 5. LAYER STRUCTURE ---
  const structureLayers = useMemo(() => {
      let accumulatedSN = 0;
      return genData.layers.map((layer, index) => {
          const isLast = index === genData.layers.length - 1;
          const supportMr = isLast ? genData.subgradeMr : genData.layers[index + 1].mr;
          const snRequiredForSupport = solveAashtoIterative(supportMr, totalESALsDesign);
          let snNeededFromLayer = Math.max(0, snRequiredForSupport - accumulatedSN);

          const asphaltLayerNames = ["Carpeta asfáltica alto desempeño", "Carpeta asfáltica normal", "Base asfáltica"];
          const m = asphaltLayerNames.includes(layer.name) ? 1.0 : (genData.drainageCoefficient || 1.0);

          const h_in_calc = snNeededFromLayer / (layer.a * m);
          const h_cm_calc = h_in_calc * 2.54;
          const manualVal = manualThicknesses[layer.id];
          const h_cm_real = manualVal !== undefined ? manualVal : Math.ceil(h_cm_calc * 2) / 2;

          const snProvided = (h_cm_real / 2.54) * layer.a * m;
          accumulatedSN += snProvided; 

          return { ...layer, supportMr, snReq: snRequiredForSupport, m, h_in_calc, h_cm_calc, h_cm_real, snProvided };
      });
  }, [genData.layers, genData.subgradeMr, genData.drainageCoefficient, totalESALsDesign, manualThicknesses]);

  const handleRealThicknessChange = (layerId: string, val: string) => {
      const num = parseFloat(val);
      setManualThicknesses(prev => ({ ...prev, [layerId]: isNaN(num) ? 0 : num }));
  };

  const formatNum = (n: number, d: number = 2) => n.toLocaleString('en-US', { minimumFractionDigits: d, maximumFractionDigits: d });

  const generatePDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text("Memoria de Cálculo - Diseño de Pavimento", 14, 20);
    doc.setFontSize(10);
    doc.text(`Proyecto: ${genData.projectName}`, 14, 30);

    // Summary
    const datosBody = [
        ["TDPA", genData.tdpa, "Confiabilidad (R)", `${genData.reliability}%`],
        ["Periodo Diseño", `${genData.designPeriod} años`, "Módulo Subrasante", `${formatNum(genData.subgradeMr, 0)} psi`],
        ["Método Tránsito", method === 'direct' ? "Directo (Ejes Manuales)" : "Calculado (Composición)", "", ""]
    ];
    autoTable(doc, {
        startY: 35,
        head: [['Parámetro', 'Valor', 'Parámetro', 'Valor']],
        body: datosBody,
        theme: 'grid',
        headStyles: { fillColor: [41, 128, 185] },
    });

    let finalY = (doc as any).lastAutoTable.finalY || 60;

    // -- NEW: Vehicle Composition Table (If method is 'vehicles') --
    if (method === 'vehicles') {
        doc.setFontSize(14);
        doc.text("Composición Vehicular", 14, finalY + 10);

        // Filter out vehicles with 0% participation
        const vehData = VEHICLE_NAMES.map((name, index) => ({
            name,
            value: compData[index] || 0
        })).filter(item => item.value > 0);

        if (vehData.length > 0) {
            autoTable(doc, {
                startY: finalY + 15,
                head: [['Tipo de Vehículo', 'Participación (%)']],
                body: vehData.map(v => [v.name, v.value.toFixed(2) + '%']),
                theme: 'striped',
                headStyles: { fillColor: [52, 73, 94] },
                styles: { fontSize: 9 },
                margin: { left: 14, right: 100 }, // Keep it narrower
                columnStyles: { 0: { cellWidth: 80 }, 1: { cellWidth: 40, halign: 'right' } }
            });
            finalY = (doc as any).lastAutoTable.finalY || (finalY + 20);
        } else {
             doc.setFontSize(10);
             doc.text("No hay vehículos con participación > 0%.", 14, finalY + 15);
             finalY += 20;
        }
    }

    // Ejes Results
    doc.setFontSize(14);
    doc.text("Cálculo de Ejes Equivalentes (ESALs)", 14, finalY + 10);
    doc.setFontSize(10);
    doc.text(`Total ESALs de Diseño: ${formatNum(totalESALsDesign, 0)}`, 14, finalY + 18);

    const filteredEsalRows = esalRows.filter(r => r.ejesAnio > 0);
    autoTable(doc, {
        startY: finalY + 22,
        head: [['No', 'Tipo', 'L2', 'Lx(kip)', 'Ejes/Año', 'Fx', 'ESAL Diseño']],
        body: filteredEsalRows.map(r => [
            r.no, r.tipo, r.l2, r.lxKip.toFixed(2), 
            Math.round(r.ejesAnio).toLocaleString(),
            r.fx.toFixed(4),
            (r.esalAnio * growthFactor).toLocaleString(undefined, {maximumFractionDigits: 0})
        ]),
        theme: 'grid',
        styles: { fontSize: 7 },
        headStyles: { fillColor: [46, 204, 113], textColor: 255 }
    });

    finalY = (doc as any).lastAutoTable.finalY || 150;
    if (finalY > 230) { doc.addPage(); finalY = 20; }

    // Structure
    const totalSnReal = structureLayers.reduce((acc, layer) => acc + (layer.snProvided || 0), 0);
    doc.setFontSize(14);
    doc.text("Estructura de Pavimento", 14, finalY + 10);
    doc.setFontSize(10);
    doc.text(`SN Requerido (Subrasante): ${formatNum(snRequiredTotalManual, 2)}`, 14, finalY + 18);
    doc.text(`SN Real Total: ${formatNum(totalSnReal, 2)}`, 110, finalY + 18);

    autoTable(doc, {
        startY: finalY + 22,
        head: [['Capa', 'Aporte (a)', 'Dren (m)', 'E (psi)', 'SN Req', 'h calc (cm)', 'h REAL (cm)']],
        body: structureLayers.map(l => [
            l.name, l.a, l.m, formatNum(l.mr, 0), formatNum(l.snReq, 2), formatNum(l.h_cm_calc, 2), l.h_cm_real.toFixed(1)
        ]),
        theme: 'grid',
        headStyles: { fillColor: [155, 89, 182] }
    });

    // Add Subgrade Row
    autoTable(doc, {
        startY: (doc as any).lastAutoTable.finalY,
        body: [[`Subrasante`, '', '', formatNum(genData.subgradeMr, 0), '', '', '']],
        theme: 'plain',
        styles: { fontStyle: 'bold', fillColor: [240, 240, 240] }
    });

    doc.save("Memoria_Diseño_Pavimento.pdf");
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 pb-24">
       <header className="mb-6">
        <h1 className="text-3xl font-bold text-white">Diseño de Pavimento</h1>
        {method === 'direct' && (
            <div className="text-emerald-400 text-sm font-bold flex items-center gap-2 mt-2">
                <i className="fas fa-database"></i> Usando datos de Ejes Directos
            </div>
        )}
      </header>

      {/* Configuration Section (SN Seed + Visualizer) */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="col-span-1 bg-slate-800 border border-slate-700 rounded-xl p-6 shadow-lg flex flex-col justify-between">
            <div>
                <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                    <i className="fas fa-calculator text-blue-500"></i> Iteración de Diseño
                </h2>
                <div className="mb-4">
                    <label className="block text-sm font-semibold text-slate-400 mb-1">SN Semilla</label>
                    <input 
                        type="number" step="0.01" value={snSeed}
                        onChange={(e) => setSnSeed(parseFloat(e.target.value) || 0)}
                        className="w-full bg-slate-900 border border-slate-600 rounded px-4 py-3 text-white focus:border-blue-500 focus:outline-none font-mono text-lg"
                    />
                </div>
                <div className="mb-2 relative p-4 bg-slate-900/50 rounded border border-slate-700">
                     <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase tracking-wider">SN Requerido</label>
                    <div className="text-2xl font-bold font-mono text-emerald-400">{formatNum(snRequiredTotalManual, 2)}</div>
                    {snRequiredTotalManual > 0 && (
                        <div className="absolute right-4 top-1/2 -translate-y-1/2">
                             <button onClick={() => setSnSeed(Number(snRequiredTotalManual.toFixed(2)))} className="w-10 h-10 rounded-full bg-blue-600 hover:bg-blue-500 text-white flex items-center justify-center transition-all shadow-lg">
                                <i className="fas fa-sync-alt"></i>
                            </button>
                        </div>
                    )}
                </div>
            </div>
             <p className="text-xs text-slate-500 mt-2">Converge cuando SN Semilla ≈ SN Requerido.</p>
        </div>

        {/* Structure Visualizer */}
        <div className="col-span-1 md:col-span-2 bg-slate-800 border border-slate-700 rounded-xl p-6 shadow-lg overflow-x-auto">
            <h2 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                <i className="fas fa-layer-group text-purple-500"></i> Estructura Requerida
            </h2>
            <div className="flex flex-col relative pl-2 min-w-[300px]">
                {/* Headers */}
                <div className="flex items-end mb-2 text-xs font-semibold text-slate-400 uppercase px-2">
                    <div className="w-16 text-center shrink-0">h (in)</div>
                    <div className="flex-1 px-2 md:px-4">Capa</div>
                    <div className="w-16 text-right shrink-0">cm calc</div>
                    <div className="w-20 text-center shrink-0">cm real</div>
                </div>

                {/* Layers List */}
                <div className="space-y-1 relative">
                    <div className="absolute left-0 top-0 bottom-0 w-0.5 bg-slate-700/50 -ml-2"></div>
                    {structureLayers.map((layer, idx) => {
                        let bgClass = "bg-slate-700", borderClass = "border-slate-600";
                        if (layer.customCode) { bgClass = "bg-purple-900/30"; borderClass = "border-purple-600/50"; }
                        else if (idx === 0) { bgClass = "bg-slate-900/80"; } else if (idx === 1) { bgClass = "bg-slate-600"; } else { bgClass = "bg-amber-900/40"; }

                        return (
                            <div key={idx} className={`relative flex items-center p-2 rounded-lg border ${bgClass} ${borderClass}`}>
                                <div className="w-16 text-center font-mono font-bold text-slate-300 text-lg shrink-0">{formatNum(layer.h_in_calc, 2)}</div>
                                <div className="flex-1 px-2 md:px-4 border-l border-slate-600/50 mx-1 md:mx-2 overflow-hidden min-w-0">
                                    <div className="md:hidden font-bold text-white text-base truncate">{getMobileLayerName(layer)}</div>
                                    <div className="hidden md:block font-bold text-white text-base truncate">{layer.name}</div>
                                    <div className="text-xs text-slate-400 mt-1 flex flex-wrap gap-x-3 gap-y-1">
                                        <span>a: <span className="text-slate-200">{layer.a}</span></span>
                                        <span>m: <span className="text-slate-200">{layer.m}</span></span>
                                        <span title="Módulo de Soporte">Mr.Sop: <span className="text-blue-300">{formatNum(layer.supportMr, 0)}</span></span>
                                        <span className="text-orange-400 font-bold">SN: {formatNum(layer.snReq, 2)}</span>
                                    </div>
                                </div>
                                <div className="w-16 text-right font-mono text-slate-400 text-sm shrink-0">{formatNum(layer.h_cm_calc, 2)}</div>
                                <div className="w-20 ml-2 shrink-0">
                                    <input type="number" step="0.5" value={layer.h_cm_real} onChange={(e) => handleRealThicknessChange(layer.id, e.target.value)} className="w-full bg-slate-950 border border-emerald-600/50 rounded px-1 py-1 text-center font-bold text-emerald-400 font-mono" />
                                </div>
                            </div>
                        );
                    })}

                    {/* Subgrade Block */}
                    <div className="relative flex items-center p-2 rounded-lg border bg-slate-950/80 border-slate-800 mt-4 border-t-2 border-t-slate-700">
                        <div className="w-16 text-center text-slate-600 text-lg shrink-0">
                            <i className="fas fa-arrow-down"></i>
                        </div>
                        <div className="flex-1 px-4 border-l border-slate-800 mx-2">
                             <div className="font-bold text-slate-400">Terracerías / Subrasante</div>
                             <div className="text-xs text-slate-500 mt-1">
                                Módulo Resiliente: <span className="text-blue-300 font-mono text-sm">{formatNum(genData.subgradeMr, 0)} psi</span>
                             </div>
                        </div>
                        <div className="w-36 shrink-0"></div>
                    </div>
                </div>
            </div>
        </div>
      </div>

      {/* Summary Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
        <div className="bg-gradient-to-br from-blue-900/50 to-slate-900 border border-blue-800/50 p-6 rounded-xl">
             <div className="text-blue-400 text-sm font-bold uppercase">Total ESALs (1er Año)</div>
             <div className="text-3xl font-mono font-bold text-white mt-1">{formatNum(totalESALs1Year, 0)}</div>
        </div>
        <div className="bg-gradient-to-br from-emerald-900/50 to-slate-900 border border-emerald-800/50 p-6 rounded-xl">
             <div className="text-emerald-400 text-sm font-bold uppercase">Total ESALs Diseño</div>
             <div className="text-3xl font-mono font-bold text-white mt-1">{formatNum(totalESALsDesign, 0)}</div>
        </div>
      </div>

      {/* Detail Table */}
      <div className="bg-slate-900 border border-slate-700 rounded-xl overflow-hidden shadow-xl mb-8">
        <div className="overflow-x-auto">
            <table className="w-full text-sm text-left text-slate-400">
                <thead className="text-xs text-slate-200 uppercase bg-slate-800">
                    <tr>
                        <th className="px-4 py-3 text-center">No.</th>
                        <th className="px-4 py-3">Tipo</th>
                        <th className="px-4 py-3 text-center text-blue-300">L2</th>
                        <th className="px-4 py-3 text-right text-blue-300">Lx (kip)</th>
                        <th className="px-4 py-3 text-right">Ejes 1er Año</th>
                        <th className="px-4 py-3 text-right text-emerald-400">Fx</th>
                        <th className="px-4 py-3 text-right font-bold text-white bg-slate-700">ESAL Diseño</th>
                    </tr>
                </thead>
                <tbody>
                    {esalRows.map((row, index) => (
                        <tr key={index} className="border-b border-slate-800 hover:bg-slate-800/50">
                            <td className="px-4 py-3 text-center">{row.no}</td>
                            <td className="px-4 py-3 font-medium text-slate-200">{row.tipo}</td>
                            <td className="px-4 py-3 text-center font-mono">{row.l2}</td>
                            <td className="px-4 py-3 text-right font-mono">{formatNum(row.lxKip)}</td>
                            <td className="px-4 py-3 text-right">{Math.round(row.ejesAnio).toLocaleString()}</td>
                            <td className="px-4 py-3 text-right font-mono text-emerald-400">{formatNum(row.fx, 4)}</td>
                            <td className="px-4 py-3 text-right font-bold text-white bg-slate-800/30 font-mono">
                                {formatNum(row.esalAnio * growthFactor)}
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
      </div>

       <div className="flex flex-col sm:flex-row justify-end gap-4">
            <button onClick={handleSaveCalculations} className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-3 rounded-lg font-bold shadow-lg">
                <i className="fas fa-save"></i> Guardar
            </button>
            <button onClick={generatePDF} className="bg-red-600 hover:bg-red-500 text-white px-6 py-3 rounded-lg font-bold shadow-lg">
                <i className="fas fa-file-pdf"></i> PDF
            </button>
        </div>
        {isSaved && (
            <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-green-500 text-white px-6 py-3 rounded-lg shadow-lg animate-bounce pointer-events-none">
                <i className="fas fa-check-circle"></i> Guardado
            </div>
        )}
    </div>
  );
};

export default EsalsPage;

import React, { useState, useEffect, useMemo } from 'react';
import { GeneralData, CompositionData, PavementLayer, CalculationMethod, AxleInputRow } from '../types';
import { DEFAULT_COMPOSITION, DEFAULT_GENERAL_DATA, TABLE_STATIC_ROWS, VEHICLE_NAMES } from '../constants';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

// Approximation of Inverse Standard Normal Distribution (Probit)
function inverseNormalCDF(p: number): number {
    if (p <= 0 || p >= 1) return 0;
    const t = Math.sqrt(-2 * Math.log(p < 0.5 ? p : 1 - p));
    const c0 = 2.515517;
    const c1 = 0.802853;
    const c2 = 0.010328;
    const d1 = 1.432788;
    const d2 = 0.189269;
    const d3 = 0.001308;

    const x = t - ((c2 * t + c1) * t + c0) / (((d3 * t + d2) * t + d1) * t + 1);
    return p < 0.5 ? -x : x;
}

// Helper for Mobile Abbreviations
const getMobileLayerName = (layer: PavementLayer) => {
    if (layer.customCode) return layer.customCode;
    switch (layer.name) {
        case "Carpeta asfáltica alto desempeño": return "AD";
        case "Carpeta asfáltica normal": return "CA";
        case "Base asfáltica": return "BA";
        case "Base Cementada": return "BC";
        case "Base hidráulica": return "BH";
        case "Sub-Base Hidráulica": return "SB";
        default: return layer.name.substring(0, 4);
    }
};

const EsalsPage: React.FC = () => {
  // Inputs for AASHTO Design
  const [snSeed, setSnSeed] = useState<number>(2.0); 
  const [manualThicknesses, setManualThicknesses] = useState<Record<string, number>>({});
  const [isSaved, setIsSaved] = useState(false);

  // Data from previous steps
  const [method, setMethod] = useState<CalculationMethod>('vehicles');
  const [genData, setGenData] = useState<GeneralData>(DEFAULT_GENERAL_DATA);
  const [compData, setCompData] = useState<CompositionData>(DEFAULT_COMPOSITION);
  const [directRows, setDirectRows] = useState<AxleInputRow[]>([]);

  useEffect(() => {
    // Load general inputs
    const savedGen = localStorage.getItem('datosGeneralesData');
    if (savedGen) setGenData({ ...DEFAULT_GENERAL_DATA, ...JSON.parse(savedGen) });

    // Load Calculation Method
    const savedMethod = localStorage.getItem('calculationMethod') as CalculationMethod | null;
    if (savedMethod) setMethod(savedMethod);

    // Load Traffic Data sources
    const savedComp = localStorage.getItem('compVehData');
    if (savedComp) setCompData(JSON.parse(savedComp));

    const savedDirect = localStorage.getItem('directAxleData');
    if (savedDirect) setDirectRows(JSON.parse(savedDirect));

    // Load saved calculations specific to this page
    const savedEsals = localStorage.getItem('esalsData');
    if (savedEsals) {
        try {
            const parsed = JSON.parse(savedEsals);
            if (parsed.snSeed !== undefined) setSnSeed(parsed.snSeed);
            if (parsed.manualThicknesses) setManualThicknesses(parsed.manualThicknesses);
        } catch (e) { console.error(e); }
    }
  }, []);

  const handleSaveCalculations = () => {
      const dataToSave = { snSeed, manualThicknesses };
      localStorage.setItem('esalsData', JSON.stringify(dataToSave));
      setIsSaved(true);
      setTimeout(() => setIsSaved(false), 3000);
  };

  // --- 1. PREPARE TRAFFIC DATA STREAM ---
  // Returns a unified structure of { id, no, tipo, l2, lxKip, count }
  const trafficStream = useMemo(() => {
      if (method === 'direct') {
          // Direct Mode: Use the user entered rows directly
          return directRows.map((r, i) => ({
              id: r.id,
              no: i + 1,
              tipo: r.l2 === 1 ? 'Sencillo' : r.l2 === 2 ? 'Tándem' : 'Trídem',
              l2: r.l2,
              lxKip: r.lxKip,
              count: r.count
          }));
      } else {
          // Vehicle Mode: Calculate derived axles first (from AxlePage logic)
          const compObj: Record<string, number> = {};
          VEHICLE_NAMES.forEach((name, idx) => { compObj[name] = compData[idx] || 0; });
          const getVal = (key: string) => compObj[key] || 0;

          const Pvc = genData.pvc;
          const TDPA = genData.tdpa;
          let fcp = 0.5;
          if (genData.lanes === '2') fcp = 0.45;
          if (genData.lanes === '3+') fcp = 0.4;
          const TDPAcd = fcp * TDPA;
          const fvp = 0.0365 * Pvc * TDPAcd;
          const fvv = 0.0365 * (100 - Pvc) * TDPAcd;

          const formulas = [
              () => 2 * getVal("A2") * (fvp + fvv),
              () => (100 - getVal("A2") + getVal("B4")) * fvp,
              () => (getVal("B2") + getVal("C2") + getVal("T2S1") + getVal("T2S2") + getVal("T2S3") + getVal("T2S2S2")) * fvp,
              () => (2*getVal("C2R2") + 2*getVal("C3R2") + getVal("C3R3") + getVal("C2R3") + 3*getVal("T2S1R2") + 2*getVal("T2S1R3") + 2*getVal("T2S2R2") + 3*getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + getVal("T3S2R3")) * fvp,
              () => (getVal("T2S1") + getVal("T3S1")) * fvp,
              () => (getVal("C2R2") + getVal("C2R3") + getVal("T2S1R2") + getVal("T2S1R3") + getVal("T2S2R2")) * fvp,
              () => (getVal("B2") + getVal("B36") + getVal("B38") + 2*getVal("B4") + 2*getVal("C2") + getVal("C36") + getVal("C38") + 4*getVal("C2R2") + 3*getVal("C3R2") + 2*getVal("C3R3") + 3*getVal("C2R3") + 3*getVal("T2S1") + 2*getVal("T2S2") + getVal("T3S2") + getVal("T3S3") + 2*getVal("T3S1") + 5*getVal("T2S1R2") + 4*getVal("T2S1R3") + 4*getVal("T2S2R2") + 4*getVal("T3S1R2") + 3*getVal("T3S1R3") + 3*getVal("T3S2R2") + getVal("T3S2R4") + 2*getVal("T3S2R3") + getVal("T3S3S2") + 2*getVal("T2S2S2") + getVal("T3S2S2")) * fvv,
              () => (getVal("B2") + getVal("B36") + getVal("B38") + getVal("B4")) * fvv,
              () => (getVal("B36") + getVal("B4") + getVal("C36") + getVal("T3S1R3")) * fvp,
              () => (getVal("B38") + getVal("C38") + getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T3S2S2")) * fvp,
              () => (getVal("C3R3") + getVal("C2R3") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R3") + getVal("T3S2R2") + 3*getVal("T3S2R4") + 2*getVal("T3S2R3") + 2*getVal("T2S2S2") + 2*getVal("T3S2S2")) * fvp,
              () => (getVal("T2S2") + getVal("T3S2") + getVal("T3S3S2")) * fvp,
              () => (getVal("C3R2") + getVal("C3R3") + getVal("T3S1R2") + getVal("T3S2R2") + getVal("T3S2R4") + getVal("T3S2R3") + getVal("T3S3S2")) * fvp,
              () => (getVal("C36") + getVal("C38") + getVal("C3R2") + 2*getVal("C3R3") + getVal("C2R3") + getVal("T2S2") + 2*getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + 4*getVal("T3S2R4") + 3*getVal("T3S2R3") + 2*getVal("T3S3S2") + 2*getVal("T2S2S2") + 3*getVal("T3S2S2")) * fvv,
              () => getVal("T3S3S2") * fvp,
              () => (getVal("T3S3") + getVal("T2S3")) * fvp,
              () => getVal("T3S3S2") * fvv
          ];

          return TABLE_STATIC_ROWS.map((staticRow, index) => {
              // Determine L2 (Axle type code) from static row type
              let l2 = 1;
              if (staticRow[1] === "Tándem") l2 = 2;
              if (staticRow[1] === "Trídem") l2 = 3;

              // Determine Weight (Lx) from Road Type (ET_A, B, C, D)
              let weightTon = 0;
              switch(genData.roadType) {
                  case 'ET_A': weightTon = staticRow[4]; break;
                  case 'B':    weightTon = staticRow[5]; break;
                  case 'C':    weightTon = staticRow[6]; break;
                  case 'D':    weightTon = staticRow[7]; break;
                  default:     weightTon = staticRow[4];
              }
              const lxKip = weightTon * 2.20462; 

              const count = formulas[index] ? formulas[index]() : 0;

              return {
                  id: `v_row_${index}`,
                  no: staticRow[0],
                  tipo: staticRow[1],
                  l2,
                  lxKip,
                  count
              };
          });
      }
  }, [method, directRows, genData, compData]);


  // --- 2. CALCULATE ESALS (Fx Calculation) ---
  const { esalRows, growthFactor } = useMemo(() => {
    const log10 = Math.log10;
    const pow = Math.pow;

    // Gt
    const pt = genData.finalServiceability;
    const Gt = log10((4.2 - pt) / 2.7);

    // Beta 18
    const beta18 = 0.4 + (1094 / pow(snSeed + 1, 5.19));

    // Growth Factor
    const r = genData.growthRate / 100;
    const n = genData.designPeriod;
    let gf = n; 
    if (r !== 0) {
        gf = (pow(1 + r, n) - 1) / r;
    }

    // Map the Unified Traffic Stream
    const rows = trafficStream.map(item => {
        const { l2, lxKip, count } = item;

        // Fx Calculation 
        // 1. Beta X
        const numeratorBx = 0.081 * pow(lxKip + l2, 3.23);
        const denominatorBx = pow(snSeed + 1, 5.19) * pow(l2, 3.23);
        const betaX = 0.4 + (numeratorBx / denominatorBx);

        // 2. Fx Exponent
        const term1 = 4.79 * log10(18 + 1); 
        const term2 = 4.79 * log10(lxKip + l2);
        const term3 = 4.33 * log10(l2);
        const term4 = Gt / betaX;
        const term5 = Gt / beta18;

        const exponent = term1 - term2 + term3 + term4 - term5;
        const fx = 1 / pow(10, exponent);

        const esal = fx * count;

        return {
            ...item,
            ejesAnio: count,
            fx,
            esalAnio: esal
        };
    });

    return { esalRows: rows, growthFactor: gf };
  }, [snSeed, genData.finalServiceability, genData.growthRate, genData.designPeriod, trafficStream]);

  const totalESALs1Year = useMemo(() => esalRows.reduce((acc, r) => acc + r.esalAnio, 0), [esalRows]);
  const totalESALsDesign = totalESALs1Year * growthFactor;

  // --- 3 & 4. SN CALCULATIONS (Same as before) ---
  const solveAashtoIterative = (Mr: number, W18: number): number => {
    if (W18 <= 0 || Mr <= 0) return 0;
    const log10 = Math.log10;
    const pow = Math.pow;
    const abs = Math.abs;
    const p = 1 - (genData.reliability / 100);
    const Zr = inverseNormalCDF(p);
    const So = genData.standardDeviation;
    const Pt = genData.finalServiceability;
    const dPSI = 4.2 - Pt; 
    const logW18 = log10(W18);
    const zrSo = Zr * So;
    const logMrTerm = 2.32 * log10(Mr);
    const psiTerm = log10(dPSI / 2.7); 
    let currentSeed = 2.0; 
    let snReq = 0;
    let error = 1.0;
    let iterations = 0;
    while (error > 0.001 && iterations < 100) {
        iterations++;
        const denominator = 0.4 + (1094 / pow(currentSeed + 1, 5.19));
        const fraction = psiTerm / denominator;
        const beta = logW18 - zrSo - fraction - logMrTerm + 8.27;
        snReq = -1 + pow(10, beta / 9.36);
        error = abs(snReq - currentSeed);
        if (error >= 0.001) currentSeed = snReq;
    }
    return snReq > 0 ? snReq : 0;
  };

  const calculateManualSN = (Mr: number, W18: number, seed: number): number => {
    if (W18 <= 0 || Mr <= 0) return 0;
    const log10 = Math.log10;
    const pow = Math.pow;
    const p = 1 - (genData.reliability / 100);
    const Zr = inverseNormalCDF(p);
    const So = genData.standardDeviation;
    const Pt = genData.finalServiceability;
    const dPSI = 4.2 - Pt;
    const logW18 = log10(W18);
    const zrSo = Zr * So;
    const logMrTerm = 2.32 * log10(Mr);
    const psiTerm = log10(dPSI / 2.7);
    const denominator = 0.4 + (1094 / pow(seed + 1, 5.19));
    const fraction = psiTerm / denominator;
    const beta = logW18 - zrSo - fraction - logMrTerm + 8.27;
    const snReq = -1 + pow(10, beta / 9.36);
    return snReq > 0 ? snReq : 0;
  };

  const snRequiredTotalManual = useMemo(() => {
    return calculateManualSN(genData.subgradeMr, totalESALsDesign, snSeed);
  }, [totalESALsDesign, genData, snSeed]);


  // --- 5. LAYER STRUCTURE ---
  const structureLayers = useMemo(() => {
      let accumulatedSN = 0;
      return genData.layers.map((layer, index) => {
          const isLast = index === genData.layers.length - 1;
          const supportMr = isLast ? genData.subgradeMr : genData.layers[index + 1].mr;
          const snRequiredForSupport = solveAashtoIterative(supportMr, totalESALsDesign);
          let snNeededFromLayer = Math.max(0, snRequiredForSupport - accumulatedSN);

          const asphaltLayerNames = ["Carpeta asfáltica alto desempeño", "Carpeta asfáltica normal", "Base asfáltica"];
          const m = asphaltLayerNames.includes(layer.name) ? 1.0 : (genData.drainageCoefficient || 1.0);

          const h_in_calc = snNeededFromLayer / (layer.a * m);
          const h_cm_calc = h_in_calc * 2.54;
          const manualVal = manualThicknesses[layer.id];
          const h_cm_real = manualVal !== undefined ? manualVal : Math.ceil(h_cm_calc * 2) / 2;

          const snProvided = (h_cm_real / 2.54) * layer.a * m;
          accumulatedSN += snProvided; 

          return { ...layer, supportMr, snReq: snRequiredForSupport, m, h_in_calc, h_cm_calc, h_cm_real, snProvided };
      });
  }, [genData.layers, genData.subgradeMr, genData.drainageCoefficient, totalESALsDesign, manualThicknesses]);

  const handleRealThicknessChange = (layerId: string, val: string) => {
      const num = parseFloat(val);
      setManualThicknesses(prev => ({ ...prev, [layerId]: isNaN(num) ? 0 : num }));
  };

  const formatNum = (n: number, d: number = 2) => n.toLocaleString('en-US', { minimumFractionDigits: d, maximumFractionDigits: d });

  const generatePDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text("Memoria de Cálculo - Diseño de Pavimento", 14, 20);
    doc.setFontSize(10);
    doc.text(`Proyecto: ${genData.projectName}`, 14, 30);

    // Summary
    const datosBody = [
        ["TDPA", genData.tdpa, "Confiabilidad (R)", `${genData.reliability}%`],
        ["Periodo Diseño", `${genData.designPeriod} años`, "Módulo Subrasante", `${formatNum(genData.subgradeMr, 0)} psi`],
        ["Método Tránsito", method === 'direct' ? "Directo (Ejes Manuales)" : "Calculado (Composición)", "", ""]
    ];
    autoTable(doc, {
        startY: 35,
        head: [['Parámetro', 'Valor', 'Parámetro', 'Valor']],
        body: datosBody,
        theme: 'grid',
        headStyles: { fillColor: [41, 128, 185] },
    });

    let finalY = (doc as any).lastAutoTable.finalY || 60;

    // -- NEW: Vehicle Composition Table (If method is 'vehicles') --
    if (method === 'vehicles') {
        doc.setFontSize(14);
        doc.text("Composición Vehicular", 14, finalY + 10);

        // Filter out vehicles with 0% participation
        const vehData = VEHICLE_NAMES.map((name, index) => ({
            name,
            value: compData[index] || 0
        })).filter(item => item.value > 0);

        if (vehData.length > 0) {
            autoTable(doc, {
                startY: finalY + 15,
                head: [['Tipo de Vehículo', 'Participación (%)']],
                body: vehData.map(v => [v.name, v.value.toFixed(2) + '%']),
                theme: 'striped',
                headStyles: { fillColor: [52, 73, 94] },
                styles: { fontSize: 9 },
                margin: { left: 14, right: 100 }, // Keep it narrower
                columnStyles: { 0: { cellWidth: 80 }, 1: { cellWidth: 40, halign: 'right' } }
            });
            finalY = (doc as any).lastAutoTable.finalY || (finalY + 20);
        } else {
             doc.setFontSize(10);
             doc.text("No hay vehículos con participación > 0%.", 14, finalY + 15);
             finalY += 20;
        }
    }

    // Ejes Results
    doc.setFontSize(14);
    doc.text("Cálculo de Ejes Equivalentes (ESALs)", 14, finalY + 10);
    doc.setFontSize(10);
    doc.text(`Total ESALs de Diseño: ${formatNum(totalESALsDesign, 0)}`, 14, finalY + 18);

    const filteredEsalRows = esalRows.filter(r => r.ejesAnio > 0);
    autoTable(doc, {
        startY: finalY + 22,
        head: [['No', 'Tipo', 'L2', 'Lx(kip)', 'Ejes/Año', 'Fx', 'ESAL Diseño']],
        body: filteredEsalRows.map(r => [
            r.no, r.tipo, r.l2, r.lxKip.toFixed(2), 
            Math.round(r.ejesAnio).toLocaleString(),
            r.fx.toFixed(4),
            (r.esalAnio * growthFactor).toLocaleString(undefined, {maximumFractionDigits: 0})
        ]),
        theme: 'grid',
        styles: { fontSize: 7 },
        headStyles: { fillColor: [46, 204, 113], textColor: 255 }
    });

    finalY = (doc as any).lastAutoTable.finalY || 150;
    if (finalY > 230) { doc.addPage(); finalY = 20; }

    // Structure
    const totalSnReal = structureLayers.reduce((acc, layer) => acc + (layer.snProvided || 0), 0);
    doc.setFontSize(14);
    doc.text("Estructura de Pavimento", 14, finalY + 10);
    doc.setFontSize(10);
    doc.text(`SN Requerido (Subrasante): ${formatNum(snRequiredTotalManual, 2)}`, 14, finalY + 18);
    doc.text(`SN Real Total: ${formatNum(totalSnReal, 2)}`, 110, finalY + 18);

    // PDF Table for Structure - Shows Layer Modulus (l.mr) as E(psi)
    autoTable(doc, {
        startY: finalY + 22,
        head: [['Capa', 'Aporte (a)', 'Dren (m)', 'E (psi)', 'SN Req', 'h calc (cm)', 'h REAL (cm)']],
        body: structureLayers.map(l => [
            l.name, l.a, l.m, formatNum(l.mr, 0), formatNum(l.snReq, 2), formatNum(l.h_cm_calc, 2), l.h_cm_real.toFixed(1)
        ]),
        theme: 'grid',
        headStyles: { fillColor: [155, 89, 182] }
    });

    // Add Subgrade Row
    autoTable(doc, {
        startY: (doc as any).lastAutoTable.finalY,
        body: [[`Subrasante`, '', '', formatNum(genData.subgradeMr, 0), '', '', '']],
        theme: 'plain',
        styles: { fontStyle: 'bold', fillColor: [240, 240, 240] }
    });

    doc.save("Memoria_Diseño_Pavimento.pdf");
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 pb-24">
       <header className="mb-6">
        <h1 className="text-3xl font-bold text-white">Diseño de Pavimento</h1>
        {method === 'direct' && (
            <div className="text-emerald-400 text-sm font-bold flex items-center gap-2 mt-2">
                <i className="fas fa-database"></i> Usando datos de Ejes Directos
            </div>
        )}
      </header>

      {/* Configuration Section (SN Seed + Visualizer) */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="col-span-1 bg-slate-800 border border-slate-700 rounded-xl p-4 sm:p-6 shadow-lg flex flex-col justify-between">
            <div>
                <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                    <i className="fas fa-calculator text-blue-500"></i> Iteración de Diseño
                </h2>
                <div className="mb-4">
                    <label className="block text-sm font-semibold text-slate-400 mb-1">SN Semilla</label>
                    <input 
                        type="number" step="0.01" value={snSeed}
                        onChange={(e) => setSnSeed(parseFloat(e.target.value) || 0)}
                        className="w-full bg-slate-900 border border-slate-600 rounded px-4 py-3 text-white focus:border-blue-500 focus:outline-none font-mono text-lg"
                    />
                </div>
                <div className="mb-2 relative p-4 bg-slate-900/50 rounded border border-slate-700">
                     <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase tracking-wider">SN Requerido</label>
                    <div className="text-2xl font-bold font-mono text-emerald-400">{formatNum(snRequiredTotalManual, 2)}</div>
                    {snRequiredTotalManual > 0 && (
                        <div className="absolute right-4 top-1/2 -translate-y-1/2">
                             <button onClick={() => setSnSeed(Number(snRequiredTotalManual.toFixed(2)))} className="w-10 h-10 rounded-full bg-blue-600 hover:bg-blue-500 text-white flex items-center justify-center transition-all shadow-lg">
                                <i className="fas fa-sync-alt"></i>
                            </button>
                        </div>
                    )}
                </div>
            </div>
             <p className="text-xs text-slate-500 mt-2">Converge cuando SN Semilla ≈ SN Requerido.</p>
        </div>

        {/* Structure Visualizer - Responsive with Scroll */}
        <div className="col-span-1 md:col-span-2 bg-slate-800 border border-slate-700 rounded-xl p-4 sm:p-6 shadow-lg overflow-x-auto">
            <h2 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                <i className="fas fa-layer-group text-purple-500"></i> Estructura Requerida
            </h2>
            {/* min-w-[650px] forces horizontal scroll on mobile, preventing column collapse */}
            <div className="flex flex-col relative pl-2 min-w-[650px]">
                {/* Headers */}
                <div className="flex items-end mb-2 text-xs font-semibold text-slate-400 uppercase px-2">
                    <div className="w-16 text-center shrink-0">h (in)</div>
                    <div className="flex-1 px-2 md:px-4">Capa</div>
                    <div className="w-16 text-right shrink-0">cm calc</div>
                    <div className="w-20 text-center shrink-0">cm real</div>
                </div>

                {/* Layers List */}
                <div className="space-y-1 relative">
                    <div className="absolute left-0 top-0 bottom-0 w-0.5 bg-slate-700/50 -ml-2"></div>
                    {structureLayers.map((layer, idx) => {
                        let bgClass = "bg-slate-700", borderClass = "border-slate-600";
                        if (layer.customCode) { bgClass = "bg-purple-900/30"; borderClass = "border-purple-600/50"; }
                        else if (idx === 0) { bgClass = "bg-slate-900/80"; } else if (idx === 1) { bgClass = "bg-slate-600"; } else { bgClass = "bg-amber-900/40"; }

