                                    <div className="text-xs text-slate-400 mt-1 flex flex-wrap gap-x-3 gap-y-1">
                                        <span>a: <span className="text-slate-200">{layer.a}</span></span>
                                        <span>m: <span className="text-slate-200">{layer.m}</span></span>
                                        <span title="Módulo de Soporte usado para cálculo">Mr.Sop: <span className="text-blue-300">{formatNum(layer.supportMr, 0)}</span></span>
                                        <span className="text-orange-400 font-bold">SN: {formatNum(layer.snReq, 2)}</span>
                                    </div>
                                </div>
                                <div className="w-16 text-right font-mono text-slate-400 text-sm shrink-0">{formatNum(layer.h_cm_calc, 2)}</div>
                                <div className="w-20 ml-2 shrink-0">
                                    <input type="number" step="0.5" value={layer.h_cm_real} onChange={(e) => handleRealThicknessChange(layer.id, e.target.value)} className="w-full bg-slate-950 border border-emerald-600/50 rounded px-1 py-1 text-center font-bold text-emerald-400 font-mono" />
                                </div>
                            </div>
                        );
                    })}

                    {/* Subgrade Block - Aligned Columns */}
                    <div className="relative flex items-center p-2 rounded-lg border bg-slate-950/80 border-slate-800 mt-4 border-t-2 border-t-slate-700 min-w-max">
                        <div className="w-16 text-center text-slate-600 text-lg shrink-0">
                            <i className="fas fa-arrow-down"></i>
                        </div>
                        <div className="flex-1 px-2 md:px-4 border-l border-slate-800 mx-1 md:mx-2">
                             <div className="font-bold text-slate-400">Terracerías / Subrasante</div>
                             <div className="text-xs text-slate-500 mt-1">
                                Módulo Resiliente: <span className="text-blue-300 font-mono text-sm">{formatNum(genData.subgradeMr, 0)} psi</span>
                             </div>
                        </div>
                        <div className="w-16 shrink-0"></div>
                        <div className="w-20 ml-2 shrink-0"></div>
                    </div>
                </div>
            </div>
            <div className="md:hidden text-center text-xs text-slate-500 mt-2 italic">
                <i className="fas fa-arrows-alt-h mr-1"></i> Desliza horizontalmente para ver todos los datos
            </div>
        </div>
      </div>

      {/* Summary Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
        <div className="bg-gradient-to-br from-blue-900/50 to-slate-900 border border-blue-800/50 p-6 rounded-xl">
             <div className="text-blue-400 text-sm font-bold uppercase">Total ESALs (1er Año)</div>
             <div className="text-3xl font-mono font-bold text-white mt-1">{formatNum(totalESALs1Year, 0)}</div>
        </div>
        <div className="bg-gradient-to-br from-emerald-900/50 to-slate-900 border border-emerald-800/50 p-6 rounded-xl">
             <div className="text-emerald-400 text-sm font-bold uppercase">Total ESALs Diseño</div>
             <div className="text-3xl font-mono font-bold text-white mt-1">{formatNum(totalESALsDesign, 0)}</div>
        </div>
      </div>

      {/* Detail Table */}
      <div className="bg-slate-900 border border-slate-700 rounded-xl overflow-hidden shadow-xl mb-8">
        <div className="overflow-x-auto">
            <table className="w-full text-sm text-left text-slate-400">
                <thead className="text-xs text-slate-200 uppercase bg-slate-800">
                    <tr>
                        <th className="px-4 py-3 text-center">No.</th>
                        <th className="px-4 py-3">Tipo</th>
                        <th className="px-4 py-3 text-center text-blue-300">L2</th>
                        <th className="px-4 py-3 text-right text-blue-300">Lx (kip)</th>
                        <th className="px-4 py-3 text-right">Ejes 1er Año</th>
                        <th className="px-4 py-3 text-right text-emerald-400">Fx</th>
                        <th className="px-4 py-3 text-right font-bold text-white bg-slate-700">ESAL Diseño</th>
                    </tr>
                </thead>
                <tbody>
                    {esalRows.map((row, index) => (
                        <tr key={index} className="border-b border-slate-800 hover:bg-slate-800/50">
                            <td className="px-4 py-3 text-center">{row.no}</td>
