            theme: 'striped',
            styles: { fontSize: 8 },
            columnStyles: { 0: { cellWidth: 100 } }
        });
        finalY = (doc as any).lastAutoTable.finalY;
    }

    // Results
    doc.setFontSize(12);
    doc.text("Resultados de Diseño", 14, finalY + 15);

    const resultsBody = [
        ["Ejes Equivalentes (ESALs) de Diseño", formatNum(totalESALsDesign, 0)],
        ["Número Estructural (SN) Requerido", formatNum(snRequiredTotalManual, 3)],
        ["SN Semilla (Iteración)", formatNum(snSeed, 2)]
    ];

    autoTable(doc, {
        startY: finalY + 20,
        body: resultsBody,
        theme: 'plain',
        styles: { fontSize: 11, fontStyle: 'bold' }
    });

    finalY = (doc as any).lastAutoTable.finalY;

    // Structure
    doc.text("Estructura de Pavimento Propuesta", 14, finalY + 15);
    const structureBody = structureLayers.map(l => [
        l.name,
        formatNum(l.mr, 0),
        l.a,
        l.m,
        formatNum(l.snReq, 2),
        formatNum(l.h_cm_calc, 2),
        formatNum(l.h_cm_real, 2)
    ]);

    autoTable(doc, {
        startY: finalY + 20,
        head: [['Capa', 'Módulo (psi)', 'a', 'm', 'SN Req', 'Esp. Calc', 'Esp. Real']],
        body: structureBody,
        theme: 'grid',
        headStyles: { fillColor: [22, 160, 133] }
    });

    doc.save("diseno_pavimento.pdf");
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 pb-32">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-white mb-2">Diseño de Pavimento</h1>
        <p className="text-slate-400">Cálculo de espesores según AASHTO-93</p>
      </header>

      {/* Inputs Section */}
      <div className="bg-slate-800 border border-slate-700 rounded-xl p-6 mb-8">
         <h3 className="text-xl font-bold text-white mb-4">Configuración de Diseño</h3>
         <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div>
                 <label className="block text-sm text-slate-400 mb-1">SN Semilla (Iteración)</label>
                 <div className="flex items-center gap-4">
                     <input
                        type="number"
                        value={snSeed}
                        onChange={(e) => setSnSeed(parseFloat(e.target.value))}
                        step="0.1"
                        className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-blue-500 outline-none"
                     />
                     <div className="text-xs text-slate-500">
                        Valor inicial para iteraciones.
                     </div>
                 </div>
             </div>
         </div>
      </div>

      {/* Results Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div className="bg-slate-800/50 border border-slate-700 p-6 rounded-xl">
              <div className="text-sm text-slate-400 mb-1">ESALs DE DISEÑO</div>
              <div className="text-3xl font-bold text-blue-400">{formatNum(totalESALsDesign, 0)}</div>
              <div className="text-xs text-slate-500 mt-2">
                  1er Año: {formatNum(totalESALs1Year, 0)}
              </div>
          </div>
          <div className="bg-slate-800/50 border border-slate-700 p-6 rounded-xl">
              <div className="text-sm text-slate-400 mb-1">SN REQUERIDO</div>
              <div className="text-3xl font-bold text-emerald-400">{formatNum(snRequiredTotalManual, 3)}</div>
