                    ? <><i className="fas fa-exclamation-triangle"></i> Ajustar Semilla</> 
                    : <><i className="fas fa-check-circle text-green-500"></i> Convergencia OK</>}
                 <p className="text-xs mt-1">Se recomienda ajustar semilla cuando SN Semilla ≈ SN Requerido.</p>
              </div>
          </div>
      </div>

      {/* Layer Structure Table */}
      <div className="bg-slate-900 border border-slate-700 rounded-xl overflow-hidden shadow-xl mb-8">
