                    </tbody>
                </table>
              </div>

              {/* Mobile View - Enhanced for Readability */}
              <div className="md:hidden space-y-3">
                    <div className="flex text-xs font-bold text-slate-500 px-3 uppercase tracking-wider">
                        <div className="flex-grow">Capa</div>
                        <div className="w-16 text-center">Calc</div>
                        <div className="w-20 text-center">Real (cm)</div>
                    </div>
                    {structureLayers.map((layer, index) => (
                        <div key={layer.id} className="bg-slate-800 border border-slate-700 p-3 rounded-lg shadow-sm">
                            <div className="flex items-center gap-3">
                                {/* Layer Name & Details */}
                                <div className="flex-grow min-w-0">
                                    <div className="text-sm font-bold text-white leading-tight mb-1 break-words">
                                        {layer.name}
                                    </div>
                                    {/* Compact Details Grid */}
                                    <div className="grid grid-cols-2 gap-x-2 gap-y-1 text-[10px] text-slate-400">
                                        <div>Mr: <span className="text-slate-300">{formatNum(layer.supportMr, 0)}</span></div>
                                        <div>a: <span className="text-slate-300">{layer.a}</span></div>
                                        <div>m: <span className="text-slate-300">{layer.m}</span></div>
                                        <div className="text-orange-400 font-semibold">SN: {formatNum(layer.snReq)}</div>
                                    </div>
                                </div>

                                {/* Calculated Thickness */}
                                <div className="w-16 flex flex-col items-center justify-center border-l border-slate-700 pl-2">
                                    <span className="text-xs font-mono text-slate-400">{formatNum(layer.h_cm_calc)}</span>
                                </div>

                                {/* Input Real Thickness */}
                                <div className="w-20 pl-2">
                                    <input
                                        type="number"
                                        value={layer.h_cm_real}
                                        onChange={(e) => handleRealThicknessChange(layer.id, e.target.value)}
                                        className="w-full bg-slate-900 border border-slate-600 rounded px-1 py-2 text-center text-white font-bold text-sm focus:border-blue-500 outline-none transition-colors"
                                        onClick={(e) => (e.target as HTMLInputElement).select()}
                                    />
                                </div>
                            </div>
                        </div>
                    ))}

                    {/* Subgrade Info Mobile */}
                    <div className="bg-slate-900/50 p-3 rounded border border-slate-800 text-xs text-slate-400 flex justify-between items-center">
                         <span>Terracerías / Subrasante</span>
                         <span>Módulo Resiliente: <strong className="text-blue-400">{formatNum(genData.subgradeMr, 0)} psi</strong></span>
                    </div>
              </div>
          </div>
      </div>

      {/* Actions */}
      <div className="fixed bottom-0 left-0 right-0 bg-slate-900/90 backdrop-blur-md border-t border-slate-800 p-4 z-40">
        <div className="max-w-7xl mx-auto flex justify-end gap-4">
             <button 
                onClick={handleSaveCalculations}
                className="bg-slate-700 hover:bg-slate-600 text-white px-4 py-3 rounded-lg font-bold flex items-center gap-2"
            >
                <i className="fas fa-save"></i> <span className="hidden sm:inline">Guardar</span>
            </button>
            <button 
