             ) : (
                 <>
                    <div className="absolute top-0 left-0 w-1 h-full bg-green-500"></div>
                    <div className="text-green-400 font-bold text-lg"><i className="fas fa-check-circle"></i> Convergencia</div>
                    <div className="text-slate-500 text-xs text-center">SN Semilla ≈ SN Requerido</div>
                 </>
             )}
          </div>
      </div>

      {/* Layer Structure Table */}
      <div className="bg-slate-900 border border-slate-700 rounded-xl overflow-hidden shadow-xl mb-8">
          <div className="p-4 bg-slate-800 border-b border-slate-700 flex justify-between items-center">
              <h3 className="font-bold text-white text-lg">Estructura Requerida</h3>
          </div>

          <div className="p-4">
              {/* Desktop View */}
              <div className="hidden md:block overflow-x-auto">
                <table className="w-full text-sm text-left text-slate-400">
                    <thead className="text-xs text-slate-200 uppercase bg-slate-800/50">
                        <tr>
                            <th className="px-4 py-3">Capa</th>
                            <th className="px-4 py-3 text-center">a</th>
